def rsa_key_gen(p, q):
    n = p * q
    phi = (p-1)*(q-1)
    e = 65537
    d = pow(e, -1, phi)
    return (e, n), (d, n)

def rsa_encrypt(m, public_key):
    e, n = public_key
    return pow(m, e, n)

def rsa_decrypt(c, private_key):
    d, n = private_key
    return pow(c, d, n)

# Example usage
p, q = 61, 53
public, private = rsa_key_gen(p, q)
message = 65
cipher = rsa_encrypt(message, public)
plain = rsa_decrypt(cipher, private)
print(f'Decrypted: {plain}') # Output: 65
